// Phase 4 — Routing Maturity Tracker
// Groups vault qa entries by (domain, model), computes Laplace-smoothed success
// rate from success_flag metadata posted by /v1/feedback (Phase 3), and emits
// `mature=true` for (domain, model) pairs with >=30 samples and smoothed
// success >= 0.85.  Math intentionally identical to the crypto outcome_tracker
// Bayesian update (ML-03) — same trust profile, same persistence.

function _node(name) {
  try { return $(name).first().json || {}; } catch (e) { return {}; }
}

const vaultRaw = _node('Read Vault QA');
const memories = (vaultRaw && vaultRaw.memories) ? vaultRaw.memories : [];

// (domain, model) -> { accepted, corrected, total, samples_by_model }
const groups = {};
for (const mem of memories) {
  const content = mem.content || '';
  const meta = (mem.metadata && typeof mem.metadata === 'object') ? mem.metadata : {};

  // Domain — from metadata first, fallback to the 'Q (... | <domain>):' header
  // the VaultProvider writes.
  let domain = (meta.domain || '').toString().trim().toLowerCase();
  if (!domain) {
    const m = content.match(/Q \([^|]+\|\s*([a-z0-9_-]+)\)/i);
    if (m) domain = m[1].toLowerCase();
  }
  if (!domain) domain = 'general';

  // Model — present when the routing decision logged it; otherwise lump under '_default'.
  const model = (meta.routed_model || meta.model || '_default').toString();
  const key = domain + '||' + model;

  if (!groups[key]) {
    groups[key] = { domain, model, accepted: 0, corrected: 0, total: 0 };
  }
  groups[key].total += 1;

  const flag = (meta.success_flag || '').toString().toLowerCase();
  if (flag === 'accepted') groups[key].accepted += 1;
  else if (flag === 'corrected') groups[key].corrected += 1;
}

// ML-03 Bayesian update — Laplace smoothing, alpha=1.
const ALPHA = 1;
const updates = [];
let matureCount = 0;
let evaluated = 0;
for (const key in groups) {
  const g = groups[key];
  const evaluatedHere = g.accepted + g.corrected;
  if (evaluatedHere === 0) continue;
  evaluated += evaluatedHere;
  const rate = (g.accepted + ALPHA) / (evaluatedHere + 2 * ALPHA);
  // Mature threshold matches the plan: >=30 evaluated samples AND smoothed >=0.85.
  const mature = evaluatedHere >= 30 && rate >= 0.85;
  if (mature) matureCount += 1;
  updates.push({
    domain: g.domain,
    model: g.model === '_default' ? '' : g.model,
    samples: evaluatedHere,
    success_rate: Math.round(rate * 10000) / 10000,
    mature: mature
  });
}

// Persist a per-day history snapshot for trend analysis (matches the IC history
// pattern in the crypto outcome_tracker so existing dashboards can render this).
const historyKey = 'maturity_' + new Date().toISOString().slice(0, 10);
const history = ($getWorkflowStaticData('maturity_history') || {});
if (!history[historyKey]) history[historyKey] = [];
history[historyKey].push({ ts: new Date().toISOString(), matureCount, evaluated, groupCount: updates.length });
if (history[historyKey].length > 20) {
  history[historyKey] = history[historyKey].slice(-20);
}
$setWorkflowStaticData('maturity_history', history);

const summary = 'ROUTING MATURITY | ' + new Date().toISOString().slice(0, 16) + 'Z\n' +
  'Groups evaluated: ' + updates.length + '\n' +
  'Total feedback samples: ' + evaluated + '\n' +
  'Mature (cheap-routed) pairs: ' + matureCount + '\n' +
  updates.slice(0, 8).map(u => '- ' + u.domain + ' / ' + (u.model || 'default') + ' : ' + u.samples + ' samples @ ' + Math.round(u.success_rate * 100) + '%' + (u.mature ? ' [MATURE]' : '')).join('\n');

return [{ json: { updates, matureCount, evaluated, summary } }];
